import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getAllPurchaseRequests, updatePurchaseRequest } from '../../services/dataService';
import { formatDate, formatCurrency } from '../../utils/helpers';
import StatusBadge from '../../components/common/StatusBadge';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import ConfirmModal from '../../components/common/ConfirmModal';
import { FiEye, FiCheck, FiX } from 'react-icons/fi';

const AdminPurchaseRequests = () => {
  const [requests, setRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [actionModal, setActionModal] = useState({ show: false, request: null, action: '' });
  const [adminNotes, setAdminNotes] = useState('');

  useEffect(() => { fetchRequests(); }, []);

  const fetchRequests = async () => {
    try {
      const res = await getAllPurchaseRequests();
      setRequests(res.data.data);
    } catch (err) { console.error(err); }
    finally { setLoading(false); }
  };

  const handleAction = async () => {
    try {
      await updatePurchaseRequest(actionModal.request._id, {
        status: actionModal.action,
        adminNotes
      });
      setActionModal({ show: false, request: null, action: '' });
      setAdminNotes('');
      fetchRequests();
    } catch (err) { console.error(err); }
  };

  const filtered = filter === 'all' ? requests : requests.filter(r => r.status === filter);

  if (loading) return <LoadingSpinner />;

  return (
    <div>
      <div className="page-header">
        <h1>Purchase Requests</h1>
        <div className="filters-bar">
          {['all', 'pending', 'approved', 'rejected'].map(f => (
            <button key={f} className={`btn btn-sm ${filter === f ? 'btn-primary' : 'btn-outline'}`} onClick={() => setFilter(f)}>
              {f.charAt(0).toUpperCase() + f.slice(1)} ({f === 'all' ? requests.length : requests.filter(r => r.status === f).length})
            </button>
          ))}
        </div>
      </div>

      {filtered.length === 0 ? (
        <div className="empty-state"><p>No purchase requests found</p></div>
      ) : (
        <div className="table-container">
          <table>
            <thead>
              <tr>
                <th>Property</th><th>Customer</th><th>Email</th><th>Phone</th>
                <th>Status</th><th>Date</th><th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filtered.map(req => (
                <tr key={req._id}>
                  <td>{req.property?.title || 'N/A'}</td>
                  <td>{req.customerName}</td>
                  <td>{req.customerEmail}</td>
                  <td>{req.customerPhone}</td>
                  <td><StatusBadge status={req.status} /></td>
                  <td>{formatDate(req.createdAt)}</td>
                  <td>
                    <div className="btn-group">
                      <Link to={`/admin/purchase-requests/${req._id}`} className="btn btn-sm btn-outline"><FiEye /></Link>
                      {req.status === 'pending' && (
                        <>
                          <button className="btn btn-sm btn-success" onClick={() => setActionModal({ show: true, request: req, action: 'approved' })}><FiCheck /></button>
                          <button className="btn btn-sm btn-danger" onClick={() => setActionModal({ show: true, request: req, action: 'rejected' })}><FiX /></button>
                        </>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {actionModal.show && (
        <ConfirmModal
          title={`${actionModal.action === 'approved' ? 'Approve' : 'Reject'} Request`}
          message={
            <div>
              <p>Are you sure you want to {actionModal.action === 'approved' ? 'approve' : 'reject'} this purchase request from <strong>{actionModal.request?.customerName}</strong>?</p>
              <div className="form-group" style={{ marginTop: '12px' }}>
                <label>Admin Notes</label>
                <textarea className="form-control" value={adminNotes} onChange={(e) => setAdminNotes(e.target.value)} rows="3" placeholder="Add notes..." />
              </div>
            </div>
          }
          onConfirm={handleAction}
          onCancel={() => { setActionModal({ show: false, request: null, action: '' }); setAdminNotes(''); }}
          confirmText={actionModal.action === 'approved' ? 'Approve' : 'Reject'}
        />
      )}
    </div>
  );
};

export default AdminPurchaseRequests;
